
#' Display and export image analysis results
#'
#' Visualizes the results of an image analysis by displaying a results table and
#' an optional side-by-side view of the original image and its corresponding
#' segmentation mask. The function can additionally export the visualization and
#' result table to disk.
#'
#' The function is intended for post-processing and inspection of results
#' generated by image analysis pipelines such as \code{run_biopixR} or
#' \code{run_cellpose()}. Image selection is based on normalized image names as
#' used throughout the package.
#'
#' @param results_list A named list of data frames containing per-image analysis
#'  results (e.g. \code{results$pixel}). List names must correspond to normalized
#'  image names.
#' @param folder  Character string specifying the image folder that contains
#'  the original images and a \code{Results/} subdirectory with mask files.
#' @param image_name Character string specifying the normalized image name to
#'  display.
#' @param download Logical; if \code{TRUE}, a combined image-mask visualization
#'  and a CSV file with the displayed results are written to disk.
#' @param plot Logical; if \code{TRUE}, the image-mask visualization is rendered
#'  on the current graphics device. Visibility depends on the execution context
#'  (interactive vs. non-interactive).
#' @param verbose Logical; if \code{TRUE}, a textual summary of the results is
#'  printed to the console.
#'
#' @returns Invisibly returns a data frame containing the displayed results
#'  (with metadata columns removed).
#'
#' @details
#' The results table is shown using \pkg{DT} when available in an interactive
#' session. Otherwise, a viewer-based table representation is used as a
#' fallback. The visualization includes optional coordinate axes and ROI
#' identifiers derived from centroid positions.
#'
#' @export
#'
#' @examples
#' \dontrun{
#' img_dir <- system.file("images", package = "NanopixR")
#'
#' show_results(results_list = results$pixel,
#' folder = img_dir,
#' image_name = "beads2",
#' download = TRUE)
#' }
show_results <- function(results_list,
                         folder,
                         image_name,
                         download = TRUE,
                         plot = TRUE,
                         verbose = TRUE) {

  # validate input folder
  .check_folder(folder)

  # validate image name argument
  if(missing(image_name) || !is.character(image_name) || length(image_name) != 1) {
    stop("'image_name' must be a single character string.", call. = FALSE)
  }

  # validate image name argument
  lookup <- .list_images_sorted(folder)
  if(!image_name %in% lookup$norm) {
    stop("No results found for image: ", image_name, call. = FALSE)
  }

  # ensure image exists in results list
  if(!image_name %in% names(results_list)) stop("No results found for: ", image_name, call. = FALSE)

  df <- results_list[[image_name]]

  # stop if no ROIs were detected
  if(!nrow(df)) stop("No ROIs found for this image.", call. = FALSE)

  # locate original image and corresponding mask
  paths <- .show_find_image_and_mask(folder,
                                     image_name)

  # load image and mask
  img <- EBImage::readImage(paths$img_path)
  mask <- EBImage::readImage(paths$mask_path, as.is = TRUE)
  bnorm <- paths$base

  # create colored mask for visualization
  mask_color <- EBImage::colorLabels(mask)
  mask_color <- suppressWarnings(EBImage::normalize(mask_color))
  dims  <- dim(mask)
  img_height <- dims[1]
  img_width <- dims[2]

  # extract summary statistics if available
  total_rois <- if("Total_ROIs" %in% names(df)) {
    unique(df$Total_ROIs)[1]
  } else {
    nrow(df)
  }

  overall_conf <- if("Overall_Confidence" %in% names(df)) {
    round(unique(df$Overall_Confidence)[1], 3)
  } else {
    NA_real_
  }

  methode <- if("Analysis_method" %in% names(df)) {
    unique(df$Analysis_method)[1]
  } else {
    NA_character_
  }

  # ensure column exists for display consistency
  if(!"Mean_Confidence" %in% names(df)) {
    df$Mean_Confidence <- NA_real_
  }

  # optional console summary
  if(verbose) {
    conf_txt <- if(is.na(overall_conf)) "NA" else overall_conf
    cat("\n", strrep("=", 50), "\n")
    cat("Results for: ", image_name, "\n", sep = "")
    cat("--> Method: ", methode, "\n", sep = "")
    cat("--> Total ROIs: ", total_rois, "\n", sep = "")
    cat("--> Overall Confidence (avg): ", conf_txt, "\n", sep = "")
    cat(strrep("=", 50), "\n\n")
  }

  # remove global summary columns for display table
  drop_cols <- c("Image_name",
                 "Total_ROIs",
                 "Overall_Confidence",
                 "Mean_Confidence",
                 "Analysis_method")
  df_show <- df[ , setdiff(names(df), drop_cols), drop = FALSE]
  method_txt <- if(is.na(methode)) "unknown method" else methode
  conf_txt <- if(is.na(overall_conf)) "NA" else overall_conf
  caption_txt <- paste(image_name, "with", method_txt, "(Total ROIs:", total_rois,
                       ", Overall Confidence:", conf_txt, ")")

  # display table interactively if possible
  if(interactive() && requireNamespace("DT", quietly = TRUE)) {
    print(DT::datatable(df_show,
                        rownames = FALSE,
                        options = list(page_Length = 10),
                        caption = caption_txt))
  } else {
    utils::View(df_show, title = caption_txt)
    print(utils::head(df_show, 20))
  }

  # optionally display overlay plot
  if(plot) {.show_plot_image_mask(img,
                                  mask,
                                  mask_color,
                                  df,
                                  image_name)}

  # optionally export plot and CSV
  if(download) {
    out_dir <- file.path(folder, "Results")
    if(!dir.exists(out_dir)) {
      dir.create(out_dir, recursive = TRUE)
    }

    plot_file <- file.path(out_dir, paste0(bnorm, "_overview.png"))
    csv_file <- file.path(out_dir, paste0(bnorm, "_results.csv"))

    # save overlay plot
    grDevices::png(plot_file,
        width = img_width * 2,
        height = img_height,
        units = "px",
        res = 150)
    on.exit({
      grDevices::dev.off()
    }, add = TRUE)

    .show_plot_image_mask(img = img,
                          mask = mask,
                          mask_color = mask_color,
                          df = df,
                          image_name = image_name)

    # prepare CSV export table
    df_download <- df_show
    df_download$Image_name <- image_name
    df_download$Analysis_method <- methode
    df_download$Total_ROIs_All <- total_rois
    df_download$Overall_Conf_All <- overall_conf

    utils::write.csv(df_download, csv_file, row.names = FALSE)

    if(verbose) {cat("Saved under:\n",
                     "Image + Mask: ", plot_file, "\n",
                     "Table:        ", csv_file, "\n\n",
                     sep = "")}
  }
  invisible(df_show)
}
